import React from 'react';
import { View, StyleSheet } from 'react-native';
import { weatherIcons } from '../assets/weather';
import { SvgProps } from 'react-native-svg';

interface WeatherIconProps {
  iconCode: string;
  size?: number;
  color?: string;
}

export const WeatherIcon: React.FC<WeatherIconProps> = ({
  iconCode,
  size = 24,
  color = '#000'
}) => {
  // Get the SVG component for the weather code, default to clear day if not found
  const Icon = weatherIcons[iconCode as keyof typeof weatherIcons] || weatherIcons['01d'];

  return (
    <View style={[styles.container, { width: size, height: size }]}>
      <Icon width={size} height={size} fill={color} />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    alignItems: 'center',
    justifyContent: 'center',
  }
});
